25: // ApplyResourceChange implements providers.Interface.
26: func (p *erroredProvider) ApplyResourceChange(providers.ApplyResourceChangeRequest) providers.ApplyResourceChangeResponse {
27: 	var diags tfdiags.Diagnostics
28: 	diags = diags.Append(tfdiags.AttributeValue(
29: 		tfdiags.Error,
30: 		"Provider configuration is invalid",
31: 		"Cannot apply changes because this resource's associated provider configuration is invalid.",
32: 		nil, // nil attribute path means the overall configuration block
33: 	))
34: 	return providers.ApplyResourceChangeResponse{
35: 		Diagnostics: diags,
36: 	}
37: }
